var currpoint=null,infowindow=null,currmarker=null,geocoder=new google.maps.Geocoder,map=null,searmarker=null,searwindow=null,flagIcon_front=new google.maps.MarkerImage(rootUri+"content/images/taxistand.png");flagIcon_front.size=new google.maps.Size(35,46);flagIcon_front.anchor=new google.maps.Point(17,46);var MapsGoogle=function(){var b=function(){var c=new google.maps.LatLng(1.353939,103.83345);map=new google.maps.Map(document.getElementById("gmap_marker"),{zoom:13,center:c,mapTypeId:google.maps.MapTypeId.ROADMAP});infowindow=new google.maps.InfoWindow;searmarker=new google.maps.Marker({position:c,map:map,draggable:true,animation:google.maps.Animation.DROP});searwindow=new google.maps.InfoWindow({content:'<div id="iw" style="height:100px;"><strong>Instructions:</strong><br /><br />Click and drag this red marker anywhere to know the approximate postal address of that location.</div>'});searwindow.open(map,searmarker);google.maps.event.addListener(infowindow,"closeclick",function(){currpoint!=null&&currpoint.uid==""&&currmarker.setMap(null)});if(typeof taxipoints!="undefined")for(var b=0;b<taxipoints.length;b++){var d=new google.maps.Marker({position:new google.maps.LatLng(taxipoints[b].latitude,taxipoints[b].longitude),map:map,icon:flagIcon_front});google.maps.event.addListener(d,"click",function(b,c){return function(){currmarker=b;currpoint=taxipoints[c];infowindow.setContent(a(currpoint,"edit"));infowindow.open(map,b)}}(d,b))}google.maps.event.addListener(map,"click",function(d){if(d.latLng){currpoint!=null&&currpoint.uid==""&&currmarker.setMap(null);var e=new google.maps.Marker({position:d.latLng,map:map,icon:flagIcon_front}),c=[];c.uid="";c.stand_name="";c.latitude=d.latLng.lb;c.longitude=d.latLng.mb;c.gps_address="";c.taxi_stand_type="";geocoder.geocode({latLng:d.latLng},function(d){if(d&&d.length>0)c.gps_address=d[0].formatted_address;else alert("Error: Google Maps could not determine the address of this location.");google.maps.event.addListener(e,"click",function(b){return function(){currmarker=b;currpoint=c;infowindow.setContent(a(c,"add"));infowindow.open(map,b)}}(e,b));currmarker=e;currpoint=c;infowindow.setContent(a(c,"add"));infowindow.open(map,e)})}});$("#target").keypress(function(a){var b=a.keyCode||a.which;if(b===13){a.preventDefault();search()}})};function a(a){var b="<div><div class='stand-title'><h2>"+a.stand_name+"</h2></div>";b+="<div><table class='taxistand-detail' width='100%' cellspacing=0 cellpadding=0>";b+="<tr><td><label>Tax stand Name:&nbsp;&nbsp;<label></td><td><input type='text' id='standname_"+a.uid+"' value='"+a.stand_name+"'></input></td></tr>";b+="<tr><td><label>Gps Address:&nbsp;&nbsp;<label></td><td><input type='text' id='standaddr_"+a.uid+"' value='"+a.gps_address+"'></input></td></tr>";b+="<tr><td><label>Latitude:&nbsp;&nbsp;<label></td><td><input type='text' id='standlat_"+a.uid+"' value='"+a.latitude+"'></input></td></tr>";b+="<tr><td><label>Longitude:&nbsp;&nbsp;<label></td><td><input type='text' id='standlng_"+a.uid+"' value='"+a.longitude+"'></input></td></tr>";b+="<tr><td><label>Taxi stand type:&nbsp;&nbsp;<label></td><td><select id='standtype_"+a.uid+"'><option value='TAXI STAND'"+(a.taxi_stand_type=="TAXI STAND"?"selected":"")+">TAXI STAND</option><option value='TAXI STOP'"+(a.taxi_stand_type=="TAXI STOP"?"selected":"")+">TAXI STOP</option><option value='TAXI PICKUP/DROPOFF'"+(a.taxi_stand_type=="TAXI PICKUP/DROPOFF"?"selected":"")+">TAXI PICKUP/DROPOFF</option></select></td></tr>";b+="</table></div>";b+="<div>";b+="<input type='button' onclick='SaveTaxiPoint();' style='padding:5px;' id='btnstandadd_"+a.uid+"' value='Save' >&nbsp;&nbsp;";b+="<input type='button' onclick='DeleteTaxiPoint();' style='padding:5px;' id='btnstanddel_"+a.uid+"' value='Delete' >&nbsp;&nbsp;";b+="</div>";return b}return{init:function(){b()}}}();function search(){geocoder.geocode({address:$("#target").val()},function(c,a){if(a==google.maps.GeocoderStatus.OK){var b=c[0].geometry.location;searmarker.setPosition(b);showGeocode(b)}else alert("Not found: "+a)})}function showGeocode(a){geocoder.geocode({latLng:a},function(b){var a="";if(b&&b.length>0)a+="<strong>Postal Address:</strong><hr/>"+b[0].formatted_address;else a+="Sorry but Google Maps could not determine the approximate postal address of this location.";a+="<br /><br /><strong>Geo Co-ordinates</strong><hr />Latitude : "+searmarker.getPosition().lat()+"<br/>Longitude: "+searmarker.getPosition().lng();map.panTo(searmarker.getPosition());searwindow.setContent("<div id='iw'>"+a+"</div>");searwindow.open(map,searmarker)})}function DeleteTaxiPoint(){if(currpoint.uid==0){currmarker.setMap(null);return true}confirm("Are you sure to delete current taxi stand?")&&$.ajax({type:"POST",url:rootUri+"TaxiLocations/DeletePoint",dataType:"json",data:{uid:currpoint.uid},success:function(a){if(a.success=="ok"){alert("Successfully deleted!");currmarker.setMap(null)}},error:function(a){alert(a.status)}})}function SaveTaxiPoint(){if(checkInputStandInfo())if(currpoint.uid==0)$.ajax({type:"POST",url:rootUri+"TaxiLocations/AddPoint",dataType:"json",data:{stand_name:currpoint.stand_name,gps_address:currpoint.gps_address,longitude:currpoint.longitude,latitude:currpoint.latitude,taxi_stand_type:currpoint.taxi_stand_type},success:function(a){if(a.success=="ok"){currpoint.uid=a.uid;infowindow.close();alert("Successfully Added!")}},error:function(a){alert("Add failed:"+a.status);currmarker.setMap(null)}});else $.ajax({type:"POST",url:rootUri+"TaxiLocations/EditPoint",dataType:"json",data:{uid:currpoint.uid,stand_name:currpoint.stand_name,gps_address:currpoint.gps_address,longitude:currpoint.longitude,latitude:currpoint.latitude,taxi_stand_type:currpoint.taxi_stand_type},success:function(a){if(a.success=="ok"){infowindow.close();alert("Successfully saved!")}},error:function(a){alert("Edit failed: "+a.status);currmarker.setMap(null)}})}function checkInputStandInfo(){var b=$("#standname_"+currpoint.uid),a=$("#standaddr_"+currpoint.uid),d=$("#standlat_"+currpoint.uid),e=$("#standlng_"+currpoint.uid),c=$("#standtype_"+currpoint.uid);if($.trim(b.val())==""){alert("Taxi stand name cannot empty, Please input taxi stand name!");return false}if($.trim(a.val())==""){alert("Taxi stand address cannot empty, Please input address!");return false}currpoint.stand_name=b.val();currpoint.gps_address=a.val();currpoint.latitude=d.val();currpoint.longitude=e.val();currpoint.taxi_stand_type=c.val();return true};